function generateAnswerId(){return Math.floor(1e3+9e3*Math.random())}
function selectEnergyLabel(){return energyLabels[Math.floor(Math.random()*energyLabels.length)]}
function detectQuestionType(e){const t=e.toLowerCase();return t.includes('他')||t.includes('她')||t.includes('感情')||t.includes('喜欢')||t.includes('爱')||t.includes('复合')||t.includes('想我')||t.includes('我们')||t.includes('前任')?'情感':t.includes('工作')||t.includes('事业')||t.includes('机会')||t.includes('升职')||t.includes('跳槽')||t.includes('面试')||t.includes('创业')||t.includes('合作')?'事业':'运势'}

function goToPage(e){document.querySelectorAll('.page').forEach(e=>e.classList.remove('active'));const t=document.getElementById(e);t&&t.classList.add('active'),'page-draw'===e?initDrawPage():'page-interpret'===e?displayInterpretation():'page-wisdom'===e?displayWisdom():'page-share'===e&&prepareShareCard()}
function selectMode(e){'general'===(state.mode=e)?goToPage('page-input'):goToPage('page-relationship-input')}
function fillQuestion(e){const t=document.getElementById('question-input');t&&(t.value=e)}
function fillPersonName(e){const t=document.getElementById('person-name-input');t&&(t.value=e)}
function submitQuestion(){const e=document.getElementById('question-input'),t=e?e.value.trim():'';return t?(state.question=t,void goToPage('page-draw')):void alert('请先输入你的问题')}
function submitRelationship(){const e=document.getElementById('person-name-input'),t=e?e.value.trim():'';return t?(state.personName=t,state.question=`关于${t}的关系`,void goToPage('page-draw')):void alert('请输入一个人的名字')}

function initDrawPage(){state.revealedCards=0,state.cards=[];const e=[...tarotCards].sort(()=>Math.random()-.5);state.cards=e.slice(0,3),document.querySelectorAll('.card').forEach(e=>e.classList.remove('revealed')),state.cards.forEach((e,t)=>{const n=document.getElementById(`card-${t+1}`),o=n?n.querySelector('.card-back'):null;o&&(o.innerHTML=`<div class="card-content"><div class="card-number">${e.nameCN}</div><div class="card-name">${e.name}</div><div class="card-meaning">${e.keywords[0]}</div></div>`)});const t=document.getElementById('btn-interpret');t&&(t.style.display='none')}

function revealCard(e){const t=document.getElementById(`card-${e}`);t&&!t.classList.contains('revealed')&&(t.classList.add('revealed'),state.revealedCards++,3===state.revealedCards&&setTimeout(()=>{const e=document.getElementById('btn-interpret');e&&(e.style.display='inline-block')},700))}

function generateInterpretation(){state.answerId=generateAnswerId(),state.energy=selectEnergyLabel(),state.questionType=detectQuestionType(state.question);let e=`宇宙答案 #${state.answerId}\n\n宇宙能量\n${state.energy}\n\n`;const[t,n,o]=state.cards;return e+=`第一张牌「${t.nameCN}」：${t.keywords.join('、')}\n此刻的状态充满着${t.keywords[0]}的能量。\n\n`,e+=`第二张牌「${n.nameCN}」：${n.keywords.join('、')}\n隐藏的因素与${n.keywords[0]}相关。\n\n`,e+=`第三张牌「${o.nameCN}」：${o.keywords.join('、')}\n未来的趋势指向${o.keywords[0]}。\n\n`,e+='宇宙想对你说：\n',e+=universeQuotes[Math.floor(Math.random()*universeQuotes.length)],state.interpretation=e,state.wisdom=universeQuotes[Math.floor(Math.random()*universeQuotes.length)],e}

function displayInterpretation(){const e=document.getElementById('display-question');e&&(e.textContent=state.question),state.cards.forEach((e,t)=>{const n=document.getElementById(`mini-card-${t+1}`);n&&(n.innerHTML=`<div style="font-size:0.55rem;color:rgba(157,123,255,0.8);margin-bottom:2px;">${['第一张','第二张','第三张'][t]}</div><div style="font-size:0.65rem;font-weight:bold;">${e.nameCN}</div><div style="font-size:0.5rem;margin-top:2px;opacity:0.7;">${e.keywords[0]}</div>`)});const t=document.getElementById('interpret-loading'),n=document.getElementById('interpret-content'),o=document.getElementById('btn-wisdom'),a=document.getElementById('answer-id');t&&(t.style.display='block'),n&&(n.style.display='none'),o&&(o.style.display='none'),a&&(a.style.display='none'),setTimeout(()=>{const e=generateInterpretation(),t=document.getElementById('interpret-text');t&&(t.textContent=e),a&&(a.textContent=`宇宙答案 #${state.answerId}`,a.style.display='block');const n=document.getElementById('interpret-loading');n&&(n.style.display='none');const o=document.getElementById('interpret-content');o&&(o.style.display='block');const s=document.getElementById('btn-wisdom');s&&(s.style.display='inline-block');const i=document.getElementById('btn-generate-card');i&&(i.style.display='inline-block')},1500)}

const shortSummaries={'The Fool':'新的旅程即将开启，保持初心与勇气','The Magician':'你拥有实现愿望的所有资源','The High Priestess':'答案在你的内心深处，倾听直觉','The Empress':'丰饶的能量正在流向你','The Emperor':'建立稳固的基础，保持理性','The Lovers':'一个重要的选择或关系浮现','The Chariot':'通过意志力克服困难，勇往直前','Strength':'真正的力量来自内在的平静','The Hermit':'需要独处反思，寻找内在的光','Wheel of Fortune':'变化正在发生，顺应时机','Justice':'因果法则运作，保持诚实','The Hanged Man':'换个角度看问题，放下控制','Death':'旧的周期结束，新生即将开始','Temperance':'寻找平衡与和谐之道','The Devil':'看见束缚，你有力量解开锁链','The Tower':'突然的变化带来觉醒','The Star':'希望之光照亮前路','The Moon':'穿越迷雾，跟随直觉','The Sun':'光明和成功的能量充满你','Judgement':'觉醒的时刻，回应内心的召唤','The World':'一个完整的周期即将圆满完成'};

function displayWisdom(){setTimeout(()=>{const e=document.getElementById('wisdom-loading'),t=document.getElementById('wisdom-content'),n=document.getElementById('wisdom-text'),o=document.getElementById('btn-share');e&&(e.style.display='none'),t&&(t.style.display='block'),o&&(o.style.display='inline-block'),n&&(n.textContent=state.wisdom||'相信你的直觉，它比理智更接近真相。')},100)}

function prepareShareCard(){const e=document.getElementById('share-question'),t=document.getElementById('share-interpret'),n=document.getElementById('share-wisdom');if(e&&(e.textContent=state.question),t){const[e,n,o]=state.cards;let a='';shortSummaries[e.name]&&(a+=`【第一张】${shortSummaries[e.name]}\n`),shortSummaries[n.name]&&(a+=`【第二张】${shortSummaries[n.name]}\n`),shortSummaries[o.name]&&(a+=`【第三张】${shortSummaries[o.name]}`),t.textContent=a}n&&(n.textContent=state.wisdom)}

